const AWS = require('aws-sdk');

const s3 = new AWS.S3({
  region: 'your-region'
});

exports.handler = async (event) => {
  const bucketName = event.Records[0].s3.bucket.name;
  const objectKey = event.Records[0].s3.object.key;

  const fileContent = await s3.getObject({ Bucket: bucketName, Key: objectKey }).promise();

  const processedData = processFile(fileContent.Body);

  const outputBucketName = 'your-output-bucket';
  const outputFileKey = objectKey + '.processed';

  try {
    await s3.putObject({
      Bucket: outputBucketName,
      Key: outputFileKey,
      Body: Buffer.from(processedData, 'utf-8')
    }).promise();

    console.log(`File processed successfully and saved to ${outputBucketName}`);
  } catch (err) {
    console.error('Error processing file:', err);
    throw new Error('Failed to process file');
  }
};

